import { useMemo, useState } from "react";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";
import { formatCurrencyValue, useCurrencyVersion } from "@/lib/currency";

const FAQS = [
  { q: "How is a car lease payment calculated?", a: "A lease payment is usually based on depreciation during the lease term plus a finance charge based on the money factor." },
  { q: "What is residual value in a car lease?", a: "Residual value is the estimated value of the vehicle at the end of the lease. A higher residual value usually lowers the monthly lease payment." },
  { q: "What is money factor in leasing?", a: "Money factor is the lease finance charge. To estimate an APR, multiply the money factor by 2400." },
  { q: "Is leasing or buying a car cheaper?", a: "Leasing often has a lower monthly payment, while buying can cost less over the long term if you keep the vehicle after the loan is paid off." },
  { q: "What happens at the end of a car lease?", a: "At lease end you usually return the vehicle, buy it for the residual value, or lease another vehicle. Mileage and condition charges may apply." },
];

const money = (v: number, d = 2) => formatCurrencyValue(Number.isFinite(v) ? v : 0, { maximumFractionDigits: d });
const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";

function loanPayment(principal: number, apr: number, months: number) {
  const r = apr / 100 / 12;
  return r === 0 ? principal / months : principal * r / (1 - Math.pow(1 + r, -months));
}

function leasePayment(msrp: number, price: number, residualPercent: number, moneyFactor: number, term: number, down: number) {
  const capCost = Math.max(0, price - down);
  const residualValue = msrp * residualPercent / 100;
  const depreciationFee = (capCost - residualValue) / term;
  const financeFee = (capCost + residualValue) * moneyFactor;
  const monthly = depreciationFee + financeFee;
  const total = monthly * term + down;
  return { capCost, residualValue, depreciationFee, financeFee, monthly, total, apr: moneyFactor * 2400 };
}

export default function AutoLeaseCalculator() {
  useCurrencyVersion();
  const [msrp, setMsrp] = useState(35000);
  const [price, setPrice] = useState(33000);
  const [residualPercent, setResidualPercent] = useState(58);
  const [moneyFactor, setMoneyFactor] = useState(0.0025);
  const [term, setTerm] = useState(36);
  const [down, setDown] = useState(3000);

  const result = useMemo(() => leasePayment(msrp, price, residualPercent, moneyFactor, term, down), [msrp, price, residualPercent, moneyFactor, term, down]);
  const buyMonthly = loanPayment(Math.max(0, price - down), Math.max(0, result.apr), 60);
  const rows = [
    { option: "Lease 36mo", payment: leasePayment(35000, 33000, 58, 0.0025, 36, 3000).monthly, down: 3000, cost3: leasePayment(35000, 33000, 58, 0.0025, 36, 3000).total, cost5: leasePayment(35000, 33000, 58, 0.0025, 36, 3000).total, ownership: "Return or buyout" },
    { option: "Lease 48mo", payment: leasePayment(35000, 33000, 50, 0.0025, 48, 3000).monthly, down: 3000, cost3: leasePayment(35000, 33000, 50, 0.0025, 48, 3000).monthly * 36 + 3000, cost5: leasePayment(35000, 33000, 50, 0.0025, 48, 3000).total, ownership: "Return or buyout" },
    { option: "Finance 60mo", payment: loanPayment(30000, 6, 60), down: 3000, cost3: loanPayment(30000, 6, 60) * 36 + 3000, cost5: loanPayment(30000, 6, 60) * 60 + 3000, ownership: "Own after loan" },
    { option: "Finance 72mo", payment: loanPayment(30000, 6.5, 72), down: 3000, cost3: loanPayment(30000, 6.5, 72) * 36 + 3000, cost5: loanPayment(30000, 6.5, 72) * 60 + 3000, ownership: "Loan continues" },
    { option: "Pay Cash", payment: 0, down: 35000, cost3: 35000, cost5: 35000, ownership: "Own immediately" },
  ];

  return (
    <>
      <SEOHead title="Free Auto Lease Calculator Online - Calculate Monthly Car Lease Payment Instantly | CalcHive" description="Free online auto lease calculator. Calculate monthly car lease payment, total lease cost and compare leasing vs buying for any vehicle instantly. 100% free, no signup required." canonical="/auto-lease-calculator" keywords="free auto lease calculator, car lease calculator free online, monthly lease payment calculator free, lease vs buy calculator free, vehicle lease calculator free online" category="Financial Calculators" breadcrumbName="Free Auto Lease Calculator Online" schemaType="WebApplication" schemaApplicationCategory="CalculatorApplication" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-sky-600 dark:text-sky-400 bg-sky-50 dark:bg-sky-950/50 px-3 py-1 rounded-full mb-4 inline-block">Financial</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Auto Lease Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Estimate monthly lease payments, total lease cost, and a simple lease vs buy comparison.</p></div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8">
            {[["Vehicle MSRP", msrp, setMsrp], ["Negotiated price", price, setPrice], ["Residual value (%)", residualPercent, setResidualPercent], ["Money factor", moneyFactor, setMoneyFactor], ["Lease term months", term, setTerm], ["Down payment", down, setDown]].map(([label, value, setter]) => (
              <div key={String(label)}><label className="text-sm font-semibold text-foreground block mb-2">{String(label)}</label><input type="number" value={Number(value)} step={String(label) === "Money factor" ? "0.0001" : "1"} onChange={(e) => (setter as (v: number) => void)(Number(e.target.value))} className={inputClass} /></div>
            ))}
          </div>
          <div className="bg-gradient-to-br from-sky-500 to-sky-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Monthly Lease Payment</p><p className="text-5xl sm:text-6xl font-black text-white">{money(result.monthly)}</p></div>
          <div className="grid grid-cols-1 sm:grid-cols-3 gap-3 mt-4"><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Total lease cost</p><p className="text-lg font-extrabold text-foreground">{money(result.total)}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Residual value</p><p className="text-lg font-extrabold text-foreground">{money(result.residualValue)}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Buy payment estimate</p><p className="text-lg font-extrabold text-foreground">{money(buyMonthly)}</p></div></div>
        </section>
        <ShareButton />
        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Calculate Your Monthly Car Lease Payment for Free</h2><p className="text-muted-foreground leading-relaxed">Lease payments combine depreciation, which is the difference between capitalized cost and residual value, plus the finance charge from the money factor.</p>
          <h2 className="text-2xl font-bold text-foreground">Lease vs Buy - Which Is Better for Your Situation</h2>
          <div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold text-foreground mb-3">Lease vs Buy Comparison - $35,000 Vehicle</caption><thead className="bg-muted/60"><tr>{["Option", "Monthly Payment", "Down Payment", "Total Cost 3yr", "Total Cost 5yr", "Ownership"].map((h) => <th key={h} className="text-left py-3 px-3 font-semibold text-foreground">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{rows.map((row) => <tr key={row.option}><td className="py-2.5 px-3 font-semibold">{row.option}</td><td className="py-2.5 px-3">{money(row.payment)}</td><td className="py-2.5 px-3">{money(row.down)}</td><td className="py-2.5 px-3">{money(row.cost3)}</td><td className="py-2.5 px-3">{money(row.cost5)}</td><td className="py-2.5 px-3">{row.ownership}</td></tr>)}</tbody></table></div>
          <h2 className="text-2xl font-bold text-foreground">Free Car Lease Payment Calculator for Everyone</h2><p className="text-muted-foreground leading-relaxed">Use this vehicle lease calculator free online to compare lease payments, residual value, and finance cost before signing a lease.</p>
        </section>
        <section className="mb-8"><h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" /><RelatedTools exclude="/auto-lease-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


